namespace sv_3099d84fcf41440ba2efe00e423b6b11.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@using sv_3099d84fcf41440ba2efe00e423b6b11.Services

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto; max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeftClicked="OnMoveLeftClicked"
                          OnMoveRightClicked="OnMoveRightClicked"
                          IsMoving="MovingTaskId == task.Id" />
            }

            @if (showAddForm)
            {
                <AddTaskForm DefaultStatus="@Status"
                             OnSave="HandleSave"
                             OnCancel="() => { showAddForm = false; }" />
            }
        </div>
        <div class="card-footer p-2">
            @if (!showAddForm)
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public string Status { get; set; } = "";
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeftClicked { get; set; }
    [Parameter] public EventCallback<int> OnMoveRightClicked { get; set; }
    [Parameter] public EventCallback<AddTaskForm.AddTaskRequest> OnTaskCreated { get; set; }
    [Parameter] public int? MovingTaskId { get; set; }

    private bool showAddForm;

    private async System.Threading.Tasks.Task HandleSave(AddTaskForm.AddTaskRequest request)
    {
        await OnTaskCreated.InvokeAsync(request);
        showAddForm = false;
    }
}

@page "/board"
@using sv_3099d84fcf41440ba2efe00e423b6b11.Services
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="HandleSearchChanged" />

    <div class="row g-3">
        @foreach (var col in columns)
        {
            var colIndex = Array.IndexOf(columns, col);
            var tasksForColumn = FilteredTasks.Where(t => t.Status == col.Status).ToList();

            <KanbanColumn ColumnName="@col.Name"
                          Status="@col.Status"
                          Tasks="tasksForColumn"
                          CanMoveLeft="colIndex > 0"
                          CanMoveRight="colIndex < columns.Length - 1"
                          OnMoveLeftClicked="id => MoveTask(id, columns[colIndex - 1].Status)"
                          OnMoveRightClicked="id => MoveTask(id, columns[colIndex + 1].Status)"
                          OnTaskCreated="HandleTaskCreated"
                          MovingTaskId="movingTaskId" />
        }
    </div>
}

@code {
    private record ColumnDef(string Name, string Status);

    private static readonly ColumnDef[] columns =
    {
        new("To Do", "To Do"),
        new("In Progress", "In Progress"),
        new("Done", "Done")
    };

    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;
    private int? movingTaskId;

    private IEnumerable<TaskItem> FilteredTasks =>
        string.IsNullOrWhiteSpace(searchTerm)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync() => await LoadTasks();

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string value) => searchTerm = value;

    private async Task MoveTask(int taskId, string newStatus)
    {
        movingTaskId = taskId;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                allTasks[idx] = allTasks[idx] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleTaskCreated(AddTaskForm.AddTaskRequest request)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(request.Title, request.Assignee, request.Priority, request.DueDate);
            allTasks.Add(created with { Status = request.Status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

