@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = "";
    [Parameter] public EventCallback<AddTaskRequest> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    public record AddTaskRequest(string Title, string Assignee, string Priority, DateTime DueDate, string Status);

    private async System.Threading.Tasks.Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            errorMessage = "Title is required.";
            return;
        }

        errorMessage = null;
        isSaving = true;
        try
        {
            await OnSave.InvokeAsync(new AddTaskRequest(title.Trim(), assignee.Trim(), priority, dueDate, DefaultStatus));
        }
        finally
        {
            isSaving = false;
        }
    }

    private async System.Threading.Tasks.Task Cancel() => await OnCancel.InvokeAsync();
}
"}

